Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <map>

int main() {
    // Replace "your_word" with the specific word you want to count
    std::string wordToFind = "your_word";

    std::ifstream file("input.txt");
    if (!file.is_open()) {
        std::cerr << "Error: Unable to open the file." << std::endl;
        return 1;
    }

    std::map<std::string, int> wordCount;

    std::string line;
    while (std::getline(file, line)) {
        std::istringstream iss(line);
        std::string token;

        while (iss >> token) {
            ++wordCount[token];
        }
    }

    file.close();

    int count = 0;
    for (const auto& entry : wordCount) {
        if (entry.first == wordToFind) {
            count = entry.second;
            break;
        }
    }

    std::cout << "The word '" << wordToFind << "' appears " << count << " times in the file." << std::endl;

    return 0;
}
```

