You can create a queue data structure using two stacks in Python by implementing the following functions:
1. `enqueue`: This function adds an element to the queue.
2. `dequeue`: This function removes and returns the front element from the queue.
3. `peek`: This function returns the front element of the queue without removing it.

Here's the implementation:
```python
class Stack:
    def __init__(self):
        self.stack = []

    def push(self, item):
        self.stack.append(item)

    def pop(self):
        if not self.is_empty():
            return self.stack.pop()

    def peek(self):
        if not self.is_empty():
            return self.stack[-1]

    def is_empty(self):
        return len(self.stack) == 0

class Queue:
    def __init__(self):
        self.q1 = Stack()
        self.q2 = Stack()

    def enqueue(self, item):
        self.q1.push(item)

    def dequeue(self):
        if self.q2.is_empty():
            while not self.q1.is_empty():
                self.q2.push(self.q1.pop())
        return self.q2.pop()

    def peek(self):
        if self.q2.is_empty():
            while not self.q1.is_empty():
                self.q2.push(self.q1.pop())
        return self.q2.peek()

    def is_empty(self):
        return self.q1.is_empty() and self.q2.is_empty()

# Example usage
queue = Queue()
queue.enqueue(1)
queue.enqueue(2)
queue.enqueue(3)
print(queue.peek())  # Output: 1
print(queue.dequeue())  # Output: 1
print(queue.peek())  # Output: 2
```

In this implementation, we use two stacks, `q1` and `q2`. When an element is enqueued, it is added to `q1`. When an element is dequeued, we first transfer all elements from `q1` to `q2` (if `q2` is empty), and then pop the front element from `q2`. The `peek` function follows a similar approach, but without removing the front element.

